import { mapState } from "vuex";
export default {
  props: {
    player: Object
  },
  methods: {
    getPlayerStateAnim() {
      if (this.player.lockedIn) {
        return "static/anims/accent/champselect-player-idle.webm";
      } else if (this.player.canBan || this.player.canLockIn) {
        return "static/anims/accent/champselect-player-active.webm";
      } else {
        return "static/anims/accent/champselect-player-idle.webm";
      }
    },
    getChampionImgUrl(champId) {
      const {
        host,
        port
      } = this.$store.state.config.download;
      return `${host}:${port}/champions/${champId}.jpg`;
    },
    initiateTrade() {
      this.$socket.sendChampSelectMessage(`CHAMPSELECT_TRADE_REQUEST`, {
        data: this.player.user.summonerName
      }, (response, error) => {
        if (error) {
          console.log("Flyback error:");
          console.log(error);
        }
        console.log(response);
      });
    },
    getSpell(spell) {
      spell = spell.toLowerCase();
      const parts = spell.split("_");
      parts.forEach((part, index) => {
        parts[index] = part.charAt(0).toUpperCase() + part.slice(1);
      });
      const spellimg = parts.join("");
      const {
        host,
        port
      } = this.$store.state.config.download;
      return `${host}:${port}/summoner_spells/${spellimg}.jpg`;
    },
    acceptTrade(playerName) {
      this.$socket.sendChampSelectMessage(`CHAMPSELECT_TRADE_ACCEPT`, {
        data: playerName
      }, (response, error) => {
        if (error) {
          console.log("Flyback error:");
          console.log(error);
        }
        console.log(response);
      });
    },
    denyTrade(playerName) {
      this.$socket.sendChampSelectMessage(`CHAMPSELECT_TRADE_DENY`, {
        data: playerName
      }, (response, error) => {
        if (error) {
          console.log("Flyback error:");
          console.log(error);
        }
        console.log(response);
      });
    }
  },
  computed: mapState({
    globalState: state => state.csGlobalState,
    tradeState: state => {
      const myTrades = state.champselect.tradesTeam.filter(trade => {
        return trade.initiator.user.summonerName == state.csCurrentPlayer.user.summonerName || trade.target.user.summonerName == state.csCurrentPlayer.user.summonerName;
      });
      if (myTrades.length == 0) return;
      const mytrade = myTrades[0];
      if (mytrade.initiator.user.summonerName == state.csCurrentPlayer.user.summonerName) {
        return {
          status: "INITIATOR",
          trade: mytrade
        };
      } else if (mytrade.target.user.summonerName == state.csCurrentPlayer.user.summonerName) {
        return {
          status: "TARGET",
          trade: mytrade
        };
      } else {
        return null;
      }
    },
    canTradeWith(state) {
      if (this.player.user.summonerName == state.csCurrentPlayer.user.summonerName) {
        console.log("A");
        return false;
      }
      if (state.champselect.tradesTeam.filter(trade => {
        return trade.initiator.summonerName == this.player.summonerName || trade.target.summonerName == this.player.summonerName;
      }).length > 0) {
        console.log("B");
        return false;
      }
      return true;
    },
    currentPlayer: state => state.csCurrentPlayer
  })
};
